INSERT INTO scripts (stage, category, target_audience, sort_order, versions) VALUES (
  'Post-Call Text — Financial Planning Course Angle',
  'follow-up',
  'young-adult',
  21,
  '[{"author": "Gabriel / Benjamin", "content": "Hello, [name]!\n\nThis is Gabriel/Benjamin from themoneybeesacademy!\n\n(http://www.instagram.com/moneybeesacademy)\n\nWe spoke on the phone earlier about our financial literacy campaign. Our goal is to help young adults & NSFs develop a greater understanding of financial literacy, that''s why we are giving away this free financial planning course.\n\nWe want to raise awareness and educate more youths on the power of financial literacy, as well as empower them to take charge of their (financial) lives!💪\n\nAs part of our commitment to enhancing your financial literacy, we are offering a free 20-minute Zoom consultation alongside our course. This personalized session allows us to adapt the insights from the course to your unique financial situation and goals—providing far more value than studying the course on its own.\n\nDuring your consultation, we will:\n\n✅ Perform a comprehensive financial health check.\n\n✅ Walk you through the key financial concepts from the course.\n\n✅ Explore how these concepts directly apply to your personal circumstances.\n\n✅ Answer any questions you have about personal finance, financial planning, and more.\n\nOur goal is to ensure you leave the session empowered with actionable knowledge tailored to your needs.\n\nWe believe you''ll find our session both enlightening and directly relevant to your financial journey. It''s a valuable opportunity to receive personalized insights and begin laying a solid foundation for your financial future.\n\nThere''s absolutely no obligation beyond this free consultation—it''s simply our way of ensuring you get the most from our resources. Does that sound fair? 😁\n\nHere are the resources you''ll be receiving after the consultation!\n\nhttps://www.skool.com/finternship/about"}]'::jsonb
);